// ── Mixin with state ───────────────────────
mixin Timestamped {
  DateTime? _createdAt;

  DateTime get createdAt => _createdAt ??= DateTime.now();

  String get age {
    final diff = DateTime.now().difference(createdAt);
    return '${diff.inSeconds}s ago';
  }
}

