class EditProfilePage extends StatefulWidget {
  const EditProfilePage({super.key});
  @override State<EditProfilePage> createState() => _EditProfilePageState();
}

class _EditProfilePageState extends State<EditProfilePage> {
  bool _dirty = false;
  final _name = TextEditingController();

  @override
  Widget build(BuildContext context) {
    return PopScope(
      // ✅ Block the system pop while we have unsaved changes
      canPop: !_dirty,

      // didPop tells us whether the route actually popped.
      // false ⇒ system tried to pop but we said canPop=false; we get a chance
      // to ask the user and pop manually.
      onPopInvoked: (didPop) async {
        if (didPop) return;                  // already popped — nothing to do
        final stay = await _confirmDiscard();
        if (!stay && mounted) Navigator.of(context).pop();
      },

      child: Scaffold(
        appBar: AppBar(title: const Text('Edit Profile')),
        body: TextField(
          controller: _name,
          onChanged: (_) => setState(() => _dirty = true),
        ),
      ),
    );
  }

  Future<bool> _confirmDiscard() async {
    final keep = await showDialog<bool>(
      context: context,
      builder: (_) => AlertDialog(
        title: const Text('Discard changes?'),
        content: const Text('Your edits will be lost.'),
        actions: [
          TextButton(onPressed: () => Navigator.pop(context, true),  child: const Text('Stay')),
          TextButton(onPressed: () => Navigator.pop(context, false), child: const Text('Discard')),
        ],
      ),
    );
    return keep ?? true;                     // default: keep editing
  }
}

