  @override
  void dispose() {
    _shimmer.dispose();
    _sub?.cancel();
    super.dispose();
  }
}

// 1) The notifier holds the state
class CounterModel extends ChangeNotifier {
  int _value = 0;
  int get value => _value;
  void inc() { _value++; notifyListeners(); }
}

// 2) InheritedNotifier exposes it
class CounterScope extends InheritedNotifier<CounterModel> {
  const CounterScope({
    super.key,
    required CounterModel super.notifier,
    required super.child,
  });

  static CounterModel of(BuildContext context) {
    final scope = context
        .dependOnInheritedWidgetOfExactType<CounterScope>();
    assert(scope != null, 'CounterScope missing');
    return scope!.notifier!;
  }
}

