// ── Retry with exponential backoff + jitter ──
import 'dart:math';
Future<T> retry<T>(
  Future<T> Function() task, {
  int maxAttempts = 4,
  Duration baseDelay = const Duration(milliseconds: 300),
  bool Function(Object e)? retryIf,
}) async {
  var attempt = 0;
  while (true) {
    attempt++;
    try {
      return await task();
    } catch (e) {
      final retryable = retryIf?.call(e) ?? _defaultRetryable(e);
      if (!retryable || attempt >= maxAttempts) rethrow;
      final exp = baseDelay * (1 << (attempt - 1));        // 300ms, 600ms, 1200ms
      final jitter = Duration(milliseconds: Random().nextInt(200));
      await Future<void>.delayed(exp + jitter);
    }
  }
}

bool _defaultRetryable(Object e) =>
    e is TimeoutException ||
    (e is DioException && (e.response?.statusCode ?? 0) >= 500) ||
    (e is SocketException);

