// ── Backpressure with a single-subscription generator ──
Stream<Block> readChunks(File file) async* {
  final raf = await file.open();
  try {
    var offset = 0;
    while (true) {
      final chunk = await raf.read(64 * 1024);
      if (chunk.isEmpty) break;
      // ✅ Yield is suspended until the consumer is ready for the next chunk.
      // If the consumer is slow, this generator is paused — no buffering.
      yield Block(offset: offset, bytes: chunk);
      offset += chunk.length;
    }
  } finally {
    await raf.close();
  }
}

// Consumer with slow processing
Future<void> ingest(File f) async {
  await for (final block in readChunks(f)) {
    await db.insert(block);                 // slow disk write
    // The reader is paused inside its `await raf.read(...)` for this duration
  }
}

