// ── Bounded fan-out queue ──
// If a listener is slow, drop events for that listener only — not the source
class BoundedFanout<T> {
  final _ctrl = StreamController<T>.broadcast();
  final _queues = <Sink<T>, ListQueue<T>>{};
  final int max;
  BoundedFanout({this.max = 100});

  Stream<T> attach() {
    final out = StreamController<T>(onCancel: () {});
    _queues[out.sink] = ListQueue<T>();
    _ctrl.stream.listen((event) async {
      final q = _queues[out.sink]!;
      if (q.length >= max) q.removeFirst();    // drop oldest
      q.add(event);
      while (q.isNotEmpty) {
        out.add(q.removeFirst());
        await Future<void>.value();           // yield to event loop
      }
    });
    return out.stream;
  }

  void add(T event) => _ctrl.add(event);
}

