// Suppose libfoo.so / foo.dylib exposes:
//   int32_t hash_bytes(const uint8_t* data, int32_t len);
import 'dart:ffi';
import 'dart:io' show Platform;
import 'package:ffi/ffi.dart';

typedef _HashC   = Int32 Function(Pointer<Uint8> data, Int32 len);
typedef _HashDart = int Function(Pointer<Uint8> data, int len);

final _lib = DynamicLibrary.open(
  Platform.isMacOS  ? 'libfoo.dylib'
: Platform.isLinux  ? 'libfoo.so'
: Platform.isWindows? 'foo.dll'
: throw UnsupportedError('platform'));

final _hash = _lib.lookupFunction<_HashC, _HashDart>('hash_bytes');

int hash(List<int> bytes) {
  // Allocate native memory; copy our Dart bytes in
  final buf = calloc<Uint8>(bytes.length);
  try {
    buf.asTypedList(bytes.length).setAll(0, bytes);
    return _hash(buf, bytes.length);
  } finally {
    calloc.free(buf);            // ✅ no GC across the boundary
  }
}

// Usage — no platform channel, no main-thread bottleneck
final h = hash(utf8.encode('hello'));

