// ── Migration path: Provider → Riverpod ──
// 1. Wrap the app in ProviderScope at the same level as MultiProvider
// 2. Move services to Riverpod Providers one at a time, leaving the old MultiProvider in place for now
// 3. Replace context.watch/read with ref.watch/read in widgets that switched
// 4. When all consumers of a service are migrated, remove it from MultiProvider
// 5. Eventually drop MultiProvider entirely
//
// You can run both side-by-side during the transition. Riverpod wraps Flutter widgets;
// Provider wraps InheritedWidget; they don't conflict.

// ── MultiProvider — clean structure ──
void main() {
  runApp(
    MultiProvider(
      providers: [
        // Singletons available everywhere — eager so init errors surface immediately
        Provider<Logger>(
          create: (_) => Logger(),
          dispose: (_, logger) => logger.flush(),
          lazy: false,
        ),
        Provider<Dio>(
          create: (_) => createDio(),
          dispose: (_, dio) => dio.close(force: true),
        ),

        // Services that depend on the ones above
        ProxyProvider<Dio, AuthRepository>(
          update: (_, dio, __) => AuthRepository(dio),
        ),

        // ChangeNotifier — auto-disposed
        ChangeNotifierProvider<AuthNotifier>(
          create: (ctx) => AuthNotifier(ctx.read<AuthRepository>())..bootstrap(),
        ),
      ],
      child: const MyApp(),
    ),
  );
}

