// ── CUBIT ─────────────────────────────────────────
class CounterCubit extends Cubit<int> {
  CounterCubit() : super(0);
  void increment() => emit(state + 1);
  void decrement() => emit(state - 1);
  void reset() => emit(0);
}

// ── BLOC (full event-driven) ───────────────────────
// Events
sealed class AuthEvent {}
class LoginRequested extends AuthEvent {
  final String email, password;
  LoginRequested(this.email, this.password);
}
class LogoutRequested extends AuthEvent {}

// States
sealed class AuthState {}
class AuthInitial extends AuthState {}
class AuthLoading extends AuthState {}
class AuthSuccess extends AuthState { final User user; AuthSuccess(this.user); }
class AuthFailure extends AuthState { final String message; AuthFailure(this.message); }

// Bloc
class AuthBloc extends Bloc<AuthEvent, AuthState> {
  final AuthRepository _repo;
  AuthBloc(this._repo) : super(AuthInitial()) {
    on<LoginRequested>(_onLogin);
    on<LogoutRequested>(_onLogout);
  }

  Future<void> _onLogin(LoginRequested e, Emitter<AuthState> emit) async {
    emit(AuthLoading());
    try {
      final user = await _repo.login(e.email, e.password);
      emit(AuthSuccess(user));
    } catch (e) {
      emit(AuthFailure(e.toString()));
    }
  }

  Future<void> _onLogout(LogoutRequested e, Emitter<AuthState> emit) async {
    await _repo.logout();
    emit(AuthInitial());
  }
}

// ── UI ─────────────────────────────────────────────
BlocConsumer<AuthBloc, AuthState>(
  listener: (ctx, state) {
    if (state is AuthSuccess) ctx.go('/home');
    if (state is AuthFailure) {
      ScaffoldMessenger.of(ctx).showSnackBar(SnackBar(content: Text(state.message)));
    }
  },
  builder: (ctx, state) {
    if (state is AuthLoading) return const CircularProgressIndicator();
    return LoginForm(
      onLogin: (e, p) => ctx.read<AuthBloc>().add(LoginRequested(e, p)),
    );
  },
)

// ── Custom BlocObserver ─────────────────────────────
class AppBlocObserver extends BlocObserver {
  final AnalyticsService _analytics;
  final CrashService _crash;

  AppBlocObserver(this._analytics, this._crash);

  @override
  void onCreate(BlocBase bloc) {
    super.onCreate(bloc);
    print('[BLoC] Created: ${bloc.runtimeType}');
  }

  @override
  void onEvent(Bloc bloc, Object? event) {
    super.onEvent(bloc, event);
    print('[BLoC] Event: ${bloc.runtimeType} → $event');
  }

  @override
  void onChange(BlocBase bloc, Change change) {
    super.onChange(bloc, change);
    print('[BLoC] Change: ${bloc.runtimeType}');
    print('  From: ${change.currentState}');
    print('  To:   ${change.nextState}');
  }

  @override
  void onTransition(Bloc bloc, Transition transition) {
    super.onTransition(bloc, transition);
    // Send to analytics
    _analytics.logEvent('bloc_transition', {
      'bloc': bloc.runtimeType.toString(),
      'event': transition.event.runtimeType.toString(),
      'from': transition.currentState.runtimeType.toString(),
      'to': transition.nextState.runtimeType.toString(),
    });
  }

  @override
  void onError(BlocBase bloc, Object error, StackTrace stackTrace) {
    super.onError(bloc, error, stackTrace);
    print('[BLoC] Error in ${bloc.runtimeType}: $error');
    _crash.report(error, stackTrace, context: {
      'bloc': bloc.runtimeType.toString(),
      'state': bloc.state.toString(),
    });
  }

  @override
  void onClose(BlocBase bloc) {
    super.onClose(bloc);
    print('[BLoC] Closed: ${bloc.runtimeType}');
  }
}

// ── Register in main() ──────────────────────────────
void main() {
  Bloc.observer = AppBlocObserver(
    AnalyticsService(),
    CrashService(),
  );
  runApp(const MyApp());
}

import 'package:bloc_concurrency/bloc_concurrency.dart';
import 'package:rxdart/rxdart.dart';

sealed class SearchEvent {}
final class QueryChanged extends SearchEvent { final String q; QueryChanged(this.q); }

sealed class SearchState {}
final class Idle extends SearchState { const Idle(); }
final class Loading extends SearchState { const Loading(); }
final class Loaded extends SearchState { final List<Hit> hits; Loaded(this.hits); }

class SearchBloc extends Bloc<SearchEvent, SearchState> {
  final SearchRepo repo;
  SearchBloc(this.repo) : super(const Idle()) {
    // ✅ Restart on every new query — cancels in-flight requests
    on<QueryChanged>(
      _onQueryChanged,
      transformer: (events, mapper) => events
          .debounceTime(const Duration(milliseconds: 300))
          .distinct()
          .switchMap(mapper),
    );
  }

  Future<void> _onQueryChanged(QueryChanged e, Emitter<SearchState> emit) async {
    if (e.q.isEmpty) { emit(const Idle()); return; }
    emit(const Loading());
    final hits = await repo.search(e.q);
    if (emit.isDone) return;        // ✅ guard against late emit after cancel
    emit(Loaded(hits));
  }
}

// ── droppable — protect submit buttons ──
class CheckoutBloc extends Bloc<CheckoutEvent, CheckoutState> {
  CheckoutBloc(this.api) : super(const CheckoutIdle()) {
    on<Submitted>(_onSubmit, transformer: droppable());
    // ✅ Repeated taps while a request is in flight — silently dropped
  }
  final Api api;
  Future<void> _onSubmit(Submitted e, Emitter<CheckoutState> emit) async {
    emit(const CheckoutSending());
    try { await api.placeOrder(e.cart); emit(const CheckoutSuccess()); }
    catch (err) { emit(CheckoutError(err)); }
  }
}

// ── sequential — preserve write order ──
class NotesBloc extends Bloc<NoteEvent, NoteState> {
  NotesBloc(this.api) : super(const NoteState.empty()) {
    on<Edited>(_onEdited, transformer: sequential());
    // ✅ Two consecutive edits go in the order the user typed them
  }
  final Api api;
  Future<void> _onEdited(Edited e, Emitter<NoteState> emit) async {
    await api.save(e.id, e.content);
    emit(state.with(e));
  }
}

// ── concurrent — only when truly parallel-safe ──
on<TrackedAnalytics>(
  (e, emit) async => api.track(e.event),
  transformer: concurrent(),         // independent fires; out-of-order is fine
);

// ── BlocBuilder — render based on full state ──
BlocBuilder<AuthBloc, AuthState>(
  builder: (context, state) {
    return switch (state) {
      AuthLoading()        => const _Spinner(),
      AuthSuccess(:final user) => HomePage(user: user),
      AuthFailure(:final message) => _Error(text: message),
      _ => const SignInPage(),
    };
  },
);

// ── BlocBuilder + buildWhen — gate rebuilds ──
BlocBuilder<CartBloc, CartState>(
  buildWhen: (prev, next) => prev.items.length != next.items.length,
  builder: (_, state) => Badge(label: Text('${state.items.length}')),
);

// ── BlocSelector — pick one slice ──
BlocSelector<CartBloc, CartState, int>(
  selector: (state) => state.items.length,
  builder: (_, count) => Badge(label: Text('$count')),
);
// Rebuilds only when length changes; price changes ignored.

// ── BlocConsumer — render + side effects together ──
BlocConsumer<AuthBloc, AuthState>(
  listenWhen: (prev, next) => prev.runtimeType != next.runtimeType,
  listener: (ctx, state) {
    if (state is AuthSuccess) ctx.go('/home');
    if (state is AuthFailure) {
      ScaffoldMessenger.of(ctx).showSnackBar(SnackBar(content: Text(state.message)));
    }
  },
  buildWhen: (prev, next) => prev != next,
  builder: (ctx, state) {
    if (state is AuthLoading) return const _Spinner();
    return const SignInForm();
  },
);

// ── Standalone listener — no UI from this widget, just side effects ──
BlocListener<AuthBloc, AuthState>(
  listener: (ctx, state) {
    if (state is AuthFailure) showSnackBar(ctx, state.message);
  },
  child: child,                       // not rebuilt by listener
);

// ── ❌ Common mistake: Navigator inside builder ──
BlocBuilder<AuthBloc, AuthState>(
  builder: (ctx, state) {
    if (state is AuthSuccess) {
      Navigator.of(ctx).pushReplacementNamed('/home'); // ❌ side effect on rebuild
    }
    return const SignInForm();
  },
);

// ── Single provider per screen ──
GoRoute(
  path: '/cart',
  builder: (_, __) => BlocProvider(
