// ── 3) Shared repository — best decoupling ──
// Repository owns the source of truth; blocs subscribe to its stream.
class SessionRepository {
  final _ctrl = StreamController<Session?>.broadcast();
  Stream<Session?> get changes => _ctrl.stream;
  Session? _current;
  Session? get current => _current;

  Future<void> signIn(String email, String pwd) async {
    final s = await api.signIn(email, pwd);
    _current = s;
    _ctrl.add(s);
  }
  Future<void> signOut() async {
    await api.signOut();
    _current = null;
    _ctrl.add(null);
  }
  void dispose() => _ctrl.close();
}

// Two blocs, both subscribe — neither knows about the other
class AuthBloc extends Bloc<AuthEvent, AuthState> {
  AuthBloc(this.session) : super(const AuthInitial()) {
    _sub = session.changes.listen(_onSession);
  }
  final SessionRepository session;
  late final StreamSubscription _sub;
  void _onSession(Session? s) => add(s == null ? const SignedOut() : SignedIn(s));
  // ...
  @override Future<void> close() { _sub.cancel(); return super.close(); }
}

class CartBloc extends Bloc<CartEvent, CartState> {
  CartBloc(this.session) : super(const CartState.empty()) {
    _sub = session.changes.listen((s) {
      if (s == null) add(const ClearCart());
    });
  }
  final SessionRepository session;
  late final StreamSubscription _sub;
  @override Future<void> close() { _sub.cancel(); return super.close(); }
}

