// ── 1) try/catch — expected failures translate to state ──
class FeedBloc extends Bloc<FeedEvent, FeedState> {
  FeedBloc(this.api) : super(const FeedState.idle()) {
    on<FeedRequested>(_onRequested);
  }
  final FeedApi api;

  Future<void> _onRequested(FeedRequested e, Emitter<FeedState> emit) async {
    emit(const FeedState.loading());
    try {
      final posts = await api.fetch();
      emit(FeedState.loaded(posts));
    } on NetworkException catch (e) {
      emit(FeedState.failure(message: 'Offline — try again', cause: e));
    } on FormatException catch (e, s) {
      addError(e, s);                     // ✅ telemetry; don't mask state
      emit(const FeedState.failure(message: 'Bad data from server'));
    } catch (e, s) {
      addError(e, s);                     // unexpected — report
      emit(const FeedState.failure(message: 'Something went wrong'));
    }
  }
}

