class _ChatPageState extends State<ChatPage> with WidgetsBindingObserver {
  late final _client = ChatClient(Uri.parse('wss://api.example.com/socket'));

  @override
  void initState() { super.initState(); WidgetsBinding.instance.addObserver(this); _client.connect(); }
  @override
