// ✅ Atomic write of related values via a single JSON blob
class FilterPrefs {
  final SharedPreferences _p;
  FilterPrefs(this._p);
  static const _k = 'filters_v1';

  Filters read() {
    final raw = _p.getString(_k);
    return raw == null ? Filters.empty() : Filters.fromJson(jsonDecode(raw));
  }

  Future<void> write(Filters f) =>
      _p.setString(_k, jsonEncode(f.toJson())); // one write — no half state
}

// ❌ Anti-pattern — three independent writes can crash mid-way
// await prefs.setString('level', 'mid');
// await prefs.setBool('darkMode', true);
// await prefs.setInt('count', 12);

// ✅ Versioned keys for safe rolling migrations
Future<void> migrate(SharedPreferences p) async {
  if (p.getInt('schema') != 2) {
    final old = p.getString('theme');
    if (old != null) await p.setString('theme.v2', old);
    await p.remove('theme');
    await p.setInt('schema', 2);
  }
}

Future<Database> openAppDb() async {
  return openDatabase(
    join(await getDatabasesPath(), 'app.db'),
    version: 3,
    onCreate: (db, v) async {
      // Apply ALL migrations from scratch
      await _v1(db);
      await _v2(db);
      await _v3(db);
    },
    onUpgrade: (db, from, to) async {
      // Apply each pending migration in order, in a single transaction
      await db.transaction((txn) async {
        if (from < 2) await _v2(txn);
        if (from < 3) await _v3(txn);
      });
    },
    onDowngrade: onDatabaseDowngradeDelete, // explicit policy on rollback
  );
}

Future<void> _v1(DatabaseExecutor db) async {
  await db.execute('''
    CREATE TABLE tasks (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      title TEXT NOT NULL,
      done INTEGER NOT NULL DEFAULT 0
    )
  ''');
}

Future<void> _v2(DatabaseExecutor db) async {
  await db.execute('ALTER TABLE tasks ADD COLUMN due_at INTEGER');
  await db.execute('CREATE INDEX idx_tasks_due ON tasks(due_at)');
}

// Drop-column-style rebuild for older SQLite
Future<void> _v3(DatabaseExecutor db) async {
  await db.execute('ALTER TABLE tasks RENAME TO tasks_old');
  await db.execute('''
    CREATE TABLE tasks (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      title TEXT NOT NULL,
      done INTEGER NOT NULL DEFAULT 0,
      due_at INTEGER
    )
  ''');
  await db.execute('''
    INSERT INTO tasks (id, title, done, due_at)
    SELECT id, title, done, due_at FROM tasks_old
  ''');
  await db.execute('DROP TABLE tasks_old');
}

