// Pessimistic — wrap any multi-step write in a transaction
Future<void> markDone(Database db, int id) {
  return db.transaction((txn) async {
    final rows = await txn.query('tasks',
        where: 'id = ?', whereArgs: [id], limit: 1);
    if (rows.isEmpty) throw StateError('not found');
    if ((rows.first['done'] as int) == 1) return; // already done — no-op
    await txn.update('tasks', {'done': 1},
        where: 'id = ?', whereArgs: [id]);
    await txn.insert('audit', {'task_id': id, 'at': DateTime.now().millisecondsSinceEpoch});
  });
}

// Optimistic — version column avoids lost updates without long locks
Future<bool> editTitle(Database db, int id, String title, int expectedRev) async {
  final updated = await db.update(
    'tasks',
    {'title': title, 'rev': expectedRev + 1},
    where: 'id = ? AND rev = ?', whereArgs: [id, expectedRev],
  );
  return updated == 1; // false ⇒ someone else won — refetch and re-prompt
}

// Serialize background sync through a single mutex so it never interleaves
import 'package:synchronized/synchronized.dart';
final _syncLock = Lock();
Future<void> applyServerPatch(Database db, ServerPatch p) {
  return _syncLock.synchronized(() async {
    await db.transaction((txn) async {
      for (final op in p.ops) await op.apply(txn);
    });
  });
}

// Enable WAL once on open for better read/write concurrency
Future<Database> openWal(String path) async {
  final db = await openDatabase(path);
  await db.rawQuery('PRAGMA journal_mode=WAL');
  await db.rawQuery('PRAGMA synchronous=NORMAL'); // good default with WAL
  return db;
}

