// ── Domain hierarchy ──
sealed class AppError implements Exception { final String message; const AppError(this.message); }
class NetworkError      extends AppError { const NetworkError([super.m = 'No network']); }
class TimeoutError      extends AppError { const TimeoutError([super.m = 'Timeout']); }
class ServerError       extends AppError { final int statusCode; const ServerError(this.statusCode, [super.m = 'Server error']); }
class UnauthorizedError extends AppError { const UnauthorizedError([super.m = 'Sign in required']); }
class ForbiddenError    extends AppError { const ForbiddenError([super.m = 'No access']); }
class NotFoundError     extends AppError { const NotFoundError([super.m = 'Not found']); }
class ValidationError   extends AppError { final Map<String, String> fields; const ValidationError(super.m, this.fields); }
class CancelledError    extends AppError { const CancelledError([super.m = 'Cancelled']); }
class UnknownError      extends AppError { final Object cause; const UnknownError(this.cause, [super.m = 'Something went wrong']); }

// ── Data layer mapper (Dio example) ──
AppError mapDioError(DioException e) {
  switch (e.type) {
    case DioExceptionType.cancel: return const CancelledError();
    case DioExceptionType.connectionTimeout:
    case DioExceptionType.sendTimeout:
    case DioExceptionType.receiveTimeout: return const TimeoutError();
    case DioExceptionType.connectionError:
    case DioExceptionType.badCertificate: return const NetworkError();
    case DioExceptionType.badResponse:
      final c = e.response?.statusCode ?? 0;
      switch (c) {
        case 400: case 422: return ValidationError(
          (e.response?.data?['message'] as String?) ?? 'Invalid input',
          _extractFieldErrors(e.response?.data));
        case 401: return const UnauthorizedError();
        case 403: return const ForbiddenError();
        case 404: return const NotFoundError();
        default:  return ServerError(c);
      }
    case DioExceptionType.unknown:
      return UnknownError(e.error ?? e);
  }
}

Map<String, String> _extractFieldErrors(dynamic body) {
  if (body is Map && body['errors'] is Map) {
    return (body['errors'] as Map).map((k, v) => MapEntry('$k', '$v'));
  }
  return const {};
}

// ── Repository — only AppError leaks out ──
class UsersRepoImpl implements UsersRepository {
  final Dio _dio;
  UsersRepoImpl(this._dio);
  @override Future<User> byId(int id) async {
    try {
      final r = await _dio.get('/users/$id');
      return UserDto.fromJson(r.data).toEntity();
    } on DioException catch (e, s) {
      Error.throwWithStackTrace(mapDioError(e), s);  // ✅ rethrow as AppError
    }
  }
}

// ── Presentation — exhaustive on AppError ──
Future<void> _load() async {
  try {
    state = Loaded(await repo.byId(id));
  } on AppError catch (e) {
    state = switch (e) {
      UnauthorizedError() => const RequiresSignIn(),
      ForbiddenError()    => const NoAccess(),
      NotFoundError()     => const NotFound(),
      ValidationError(:final fields) => InvalidForm(fields),
      NetworkError() || TimeoutError() => const Offline(),
      ServerError() || UnknownError() => Failed(e.message),
      CancelledError() => state,            // user cancelled — keep current
    };
  }
}

// ── Flag client with bundled defaults ──
class FeatureFlags {
  FeatureFlags._(this._values);
  final Map<String, dynamic> _values;

  static late FeatureFlags instance;

  static Future<void> initialize() async {
    // 1) Bundled defaults
    final defaults = jsonDecode(await rootBundle.loadString('assets/flags.json'))
        as Map<String, dynamic>;

    // 2) Cached values from disk (if any)
    final secure = const FlutterSecureStorage();
    final cachedRaw = await secure.read(key: 'flags');
    final cached = cachedRaw == null
        ? const <String, dynamic>{}
        : jsonDecode(cachedRaw) as Map<String, dynamic>;

    // 3) Remote — fire-and-forget update for next launch
    final fetched = await _fetchRemoteOrNull();
    final merged = {...defaults, ...cached, if (fetched != null) ...fetched};

    if (fetched != null) {
      unawaited(secure.write(key: 'flags', value: jsonEncode(fetched)));
    }

    instance = FeatureFlags._(merged);
  }

  bool get checkoutV2Enabled    => _values['checkout_v2_enabled']     == true;
  bool get newOnboardingEnabled => _values['onboarding_v3_enabled']   == true;
  String get pricingTier        => _values['pricing_tier'] as String? ?? 'free';
}

static Future<Map<String, dynamic>?> _fetchRemoteOrNull() async {
  try {
    final remote = FirebaseRemoteConfig.instance;
    await remote.fetchAndActivate();
    return remote.getAll().map((k, v) => MapEntry(k, v.asString()));
  } catch (_) { return null; }
}

