// O(1) — constant
int getHead(List<int> list) => list[0]; // always 1 op
bool inSet(Set<int> s, int val) => s.contains(val); // hash lookup

// O(log n) — binary search
int binarySearch(List<int> sorted, int target) {
  var lo = 0, hi = sorted.length - 1;
  while (lo <= hi) {
    final mid = lo + (hi - lo) ~/ 2;
    if (sorted[mid] == target) return mid;
    if (sorted[mid] < target) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

// O(n) — linear search
int linearSearch(List<int> list, int target) {
  for (var i = 0; i < list.length; i++) {
    if (list[i] == target) return i;
  }
  return -1;
}

// O(n log n) — merge sort
List<int> mergeSort(List<int> list) {
  if (list.length <= 1) return list;
  final mid   = list.length ~/ 2;
  final left  = mergeSort(list.sublist(0, mid));
  final right = mergeSort(list.sublist(mid));
  return _merge(left, right);
}

List<int> _merge(List<int> a, List<int> b) {
  final res = <int>[];
  var i = 0, j = 0;
  while (i < a.length && j < b.length) {
    res.add(a[i] <= b[j] ? a[i++] : b[j++]);
  }
  return res..addAll(a.sublist(i))..addAll(b.sublist(j));
}

// O(n²) — bubble sort (educational only)
void bubbleSort(List<int> list) {
  for (var i = 0; i < list.length - 1; i++) {
    for (var j = 0; j < list.length - i - 1; j++) {
      if (list[j] > list[j + 1]) {
        final t = list[j]; list[j] = list[j + 1]; list[j + 1] = t;
      }
    }
  }
}

// ✅ Always prefer Dart's built-in list.sort() — it's Timsort O(n log n)

class ListNode<T> {
  T value;
  ListNode<T>? next;
  ListNode(this.value, [this.next]);
}

class LinkedList<T> {
  ListNode<T>? head;
  int _length = 0;
  int get length => _length;
  bool get isEmpty => head == null;

  // O(1) — prepend
  void prepend(T value) {
    head = ListNode(value, head);
    _length++;
  }

  // O(n) — append
  void append(T value) {
    if (head == null) { prepend(value); return; }
    var cur = head!;
    while (cur.next != null) cur = cur.next!;
    cur.next = ListNode(value);
    _length++;
  }

  // O(1) — remove head
  T? removeFirst() {
    if (head == null) return null;
    final val = head!.value;
    head = head!.next;
    _length--;
    return val;
  }

  // O(n) — remove by value
  bool remove(T value) {
    if (head == null) return false;
    if (head!.value == value) { head = head!.next; _length--; return true; }
    var cur = head!;
    while (cur.next != null) {
      if (cur.next!.value == value) {
        cur.next = cur.next!.next;
        _length--;
        return true;
      }
      cur = cur.next!;
    }
    return false;
  }

  // O(n) — reverse in-place
  void reverse() {
    ListNode<T>? prev, cur = head;
    while (cur != null) {
      final next = cur.next;
      cur.next = prev;
      prev = cur;
      cur = next;
    }
    head = prev;
  }

  List<T> toList() {
    final result = <T>[];
    var cur = head;
    while (cur != null) { result.add(cur.value); cur = cur.next; }
    return result;
  }
}

// Usage
final list = LinkedList<int>();
list.append(1); list.append(2); list.append(3);
list.prepend(0);
print(list.toList()); // [0, 1, 2, 3]
list.reverse();
print(list.toList()); // [3, 2, 1, 0]

import 'dart:collection';

// ── Stack ─────────────────────────────────────────
class Stack<T> {
  final _list = ListQueue<T>();
  void push(T item) => _list.addLast(item);
  T pop() => _list.removeLast();
  T get peek => _list.last;
  bool get isEmpty => _list.isEmpty;
  int get size => _list.length;
}

// Problem: Valid Parentheses — O(n) time, O(n) space
bool isValid(String s) {
  final stack = Stack<String>();
  const map = {'(': ')', '[': ']', '{': '}'};
  for (final c in s.split('')) {
    if (map.containsKey(c)) {
      stack.push(c);
    } else {
      if (stack.isEmpty || map[stack.pop()] != c) return false;
    }
  }
  return stack.isEmpty;
}
print(isValid('()[]{}')); // true
print(isValid('([)]'));   // false

// Problem: Min Stack — O(1) getMin
class MinStack {
  final _stack = Stack<int>();
  final _minStack = Stack<int>(); // tracks minimums

  void push(int val) {
    _stack.push(val);
    _minStack.push(_minStack.isEmpty ? val : val < _minStack.peek ? val : _minStack.peek);
  }
  int pop() { _minStack.pop(); return _stack.pop(); }
  int get top => _stack.peek;
  int get min => _minStack.peek; // O(1)!
}

// ── Queue ─────────────────────────────────────────
class Queue_<T> {
  final _list = ListQueue<T>();
  void enqueue(T item) => _list.addLast(item);
  T dequeue() => _list.removeFirst();
  T get front => _list.first;
  bool get isEmpty => _list.isEmpty;
}

// BFS on a graph
List<int> bfs(Map<int, List<int>> graph, int start) {
  final visited = <int>{};
  final queue = Queue_<int>();
  final order = <int>[];

  queue.enqueue(start);
  visited.add(start);

  while (!queue.isEmpty) {
    final node = queue.dequeue();
    order.add(node);
    for (final neighbor in graph[node] ?? []) {
      if (!visited.contains(neighbor)) {
        visited.add(neighbor);
        queue.enqueue(neighbor);
      }
    }
  }
  return order;
}

// ── TWO POINTERS ──────────────────────────────────

// Problem: Two Sum (sorted array) — O(n)
List<int>? twoSum(List<int> sorted, int target) {
  var left = 0, right = sorted.length - 1;
  while (left < right) {
    final sum = sorted[left] + sorted[right];
    if (sum == target) return [left, right];
    if (sum < target) left++;
    else right--;
  }
  return null;
}
print(twoSum([1, 2, 3, 6, 8, 11], 14)); // [3, 5] (6+8)

// Problem: Remove duplicates from sorted array in-place — O(n)
int removeDuplicates(List<int> nums) {
  if (nums.isEmpty) return 0;
  var slow = 0;
  for (var fast = 1; fast < nums.length; fast++) {
    if (nums[fast] != nums[slow]) {
      nums[++slow] = nums[fast];
    }
  }
  return slow + 1;
}

// Problem: Reverse a string in-place
void reverseString(List<String> chars) {
  var l = 0, r = chars.length - 1;
  while (l < r) {
    final tmp = chars[l]; chars[l] = chars[r]; chars[r] = tmp;
    l++; r--;
  }
}

// ── SLIDING WINDOW ─────────────────────────────────

// Problem: Max sum subarray of size k — O(n)
int maxSubarraySum(List<int> nums, int k) {
  if (nums.length < k) return 0;
  var windowSum = nums.sublist(0, k).fold(0, (a, b) => a + b);
  var maxSum = windowSum;
  for (var i = k; i < nums.length; i++) {
    windowSum += nums[i] - nums[i - k]; // slide: add new, remove old
    if (windowSum > maxSum) maxSum = windowSum;
  }
  return maxSum;
}
print(maxSubarraySum([2, 1, 5, 1, 3, 2], 3)); // 9 (5+1+3)

// Problem: Longest substring without repeating chars — O(n)
int lengthOfLongestSubstring(String s) {
  final seen = <String, int>{}; // char → last seen index
  var maxLen = 0;
  var left = 0;
  for (var right = 0; right < s.length; right++) {
    final c = s[right];
    if (seen.containsKey(c) && seen[c]! >= left) {
      left = seen[c]! + 1; // shrink window
    }
    seen[c] = right;
    if (right - left + 1 > maxLen) maxLen = right - left + 1;
  }
  return maxLen;
}
print(lengthOfLongestSubstring('abcabcbb')); // 3 (abc)

class TreeNode {
  int val;
  TreeNode? left, right;
  TreeNode(this.val, [this.left, this.right]);
}

// ── DFS — recursive, in-order ──
void inOrder(TreeNode? node, void Function(int) visit) {
  if (node == null) return;
  inOrder(node.left, visit);
  visit(node.val);
  inOrder(node.right, visit);
}

// ── DFS — iterative with explicit stack (safe on deep trees) ──
List<int> preOrderIterative(TreeNode? root) {
  final result = <int>[];
  if (root == null) return result;
  final stack = <TreeNode>[root];
  while (stack.isNotEmpty) {
    final node = stack.removeLast();
    result.add(node.val);
    if (node.right != null) stack.add(node.right!);  // push right first → left popped first
    if (node.left != null)  stack.add(node.left!);
  }
  return result;
}

// ── BFS — level order ──
import 'dart:collection';
List<List<int>> levelOrder(TreeNode? root) {
  final result = <List<int>>[];
  if (root == null) return result;
  final q = ListQueue<TreeNode>()..add(root);
  while (q.isNotEmpty) {
    final levelSize = q.length;
    final level = <int>[];
    for (var i = 0; i < levelSize; i++) {
      final node = q.removeFirst();
      level.add(node.val);
      if (node.left  != null) q.add(node.left!);
      if (node.right != null) q.add(node.right!);
    }
    result.add(level);
  }
  return result;
}

// ── Validate BST — in-order monotonic check ──
bool isValidBst(TreeNode? root) {
  int? prev;
  bool dfs(TreeNode? n) {
    if (n == null) return true;
    if (!dfs(n.left)) return false;
    if (prev != null && n.val <= prev!) return false;
    prev = n.val;
    return dfs(n.right);
  }
  return dfs(root);
}

// ── Max depth — post-order DFS ──
int maxDepth(TreeNode? n) =>
    n == null ? 0 : 1 + max(maxDepth(n.left), maxDepth(n.right));

// ── Lowest Common Ancestor — post-order DFS ──
TreeNode? lca(TreeNode? root, TreeNode a, TreeNode b) {
  if (root == null || identical(root, a) || identical(root, b)) return root;
  final l = lca(root.left, a, b);
  final r = lca(root.right, a, b);
  if (l != null && r != null) return root;
  return l ?? r;
}

import 'dart:collection';
import 'package:collection/collection.dart';   // HeapPriorityQueue

// ── BFS shortest path on unweighted graph ──
int? shortestPath(Map<int, List<int>> graph, int start, int end) {
  if (start == end) return 0;
  final visited = <int>{start};
  final q = ListQueue<(int, int)>()..add((start, 0));
  while (q.isNotEmpty) {
    final (node, dist) = q.removeFirst();
    for (final neighbor in graph[node] ?? const []) {
      if (visited.add(neighbor)) {
        if (neighbor == end) return dist + 1;
        q.add((neighbor, dist + 1));
      }
    }
  }
  return null;
}

// ── Dijkstra — shortest path with weights ──
Map<int, int> dijkstra(Map<int, List<(int, int)>> graph, int start) {
  final dist = <int, int>{start: 0};
  final pq = HeapPriorityQueue<(int, int)>((a, b) => a.$2.compareTo(b.$2));
  pq.add((start, 0));

  while (pq.isNotEmpty) {
    final (node, d) = pq.removeFirst();
    if (d > (dist[node] ?? 1 << 62)) continue;       // stale entry
    for (final (neighbor, weight) in graph[node] ?? const []) {
      final next = d + weight;
      if (next < (dist[neighbor] ?? 1 << 62)) {
        dist[neighbor] = next;
        pq.add((neighbor, next));
      }
    }
  }
  return dist;
}

// ── Topological sort — Kahn's algorithm ──
List<int>? topologicalSort(int n, List<List<int>> edges) {
  final inDegree = List<int>.filled(n, 0);
  final adj = List.generate(n, (_) => <int>[]);
  for (final e in edges) {
    adj[e[0]].add(e[1]);
    inDegree[e[1]]++;
  }
  final q = ListQueue<int>();
  for (var i = 0; i < n; i++) {
    if (inDegree[i] == 0) q.add(i);
  }
  final order = <int>[];
  while (q.isNotEmpty) {
    final node = q.removeFirst();
    order.add(node);
    for (final next in adj[node]) {
      if (--inDegree[next] == 0) q.add(next);
    }
  }
  return order.length == n ? order : null;          // null = cycle
}

// Course schedule example
void main() {
  final order = topologicalSort(4, [[0, 1], [0, 2], [1, 3], [2, 3]]);
  print(order); // [0, 1, 2, 3] or [0, 2, 1, 3]
}

// ── Brute recursion — exponential ──
int coinChangeBrute(List<int> coins, int amount) {
  if (amount == 0) return 0;
  if (amount < 0)  return -1;
  var best = -1;
  for (final c in coins) {
    final sub = coinChangeBrute(coins, amount - c);
    if (sub == -1) continue;
    if (best == -1 || sub + 1 < best) best = sub + 1;
  }
  return best;
}

// ── Step 1 → memoize (top-down DP) — O(amount × coins.length) ──
int coinChangeMemo(List<int> coins, int amount) {
  final memo = <int, int>{};
  int helper(int rem) {
    if (rem == 0) return 0;
    if (rem < 0)  return -1;
    if (memo.containsKey(rem)) return memo[rem]!;
    var best = -1;
    for (final c in coins) {
      final sub = helper(rem - c);
      if (sub == -1) continue;
      if (best == -1 || sub + 1 < best) best = sub + 1;
    }
    return memo[rem] = best;
  }
  return helper(amount);
}

// ── Step 2 → tabulate (bottom-up DP) — same complexity, no recursion ──
int coinChangeDP(List<int> coins, int amount) {
  // dp[i] = min coins to make amount i; sentinel = infinity
  final dp = List<int>.filled(amount + 1, amount + 1);
  dp[0] = 0;
  for (var i = 1; i <= amount; i++) {
    for (final c in coins) {
      if (c <= i) dp[i] = min(dp[i], dp[i - c] + 1);
    }
  }
  return dp[amount] > amount ? -1 : dp[amount];
}

// ── Edit distance — 2D DP ──
int editDistance(String a, String b) {
  final m = a.length, n = b.length;
  final dp = List.generate(m + 1, (_) => List<int>.filled(n + 1, 0));
  for (var i = 0; i <= m; i++) dp[i][0] = i;
  for (var j = 0; j <= n; j++) dp[0][j] = j;
  for (var i = 1; i <= m; i++) {
    for (var j = 1; j <= n; j++) {
      if (a[i - 1] == b[j - 1]) {
        dp[i][j] = dp[i - 1][j - 1];
      } else {
        dp[i][j] = 1 + min(min(
          dp[i - 1][j],     // delete
          dp[i][j - 1]),    // insert
          dp[i - 1][j - 1]); // replace
      }
    }
  }
  return dp[m][n];
}

// ── Space optimization — many DPs only need the last row ──
int coinChange1D(List<int> coins, int amount) {
  final dp = List<int>.filled(amount + 1, amount + 1)..[0] = 0;
  for (var i = 1; i <= amount; i++) {
    for (final c in coins) if (c <= i) dp[i] = min(dp[i], dp[i - c] + 1);
  }
  return dp[amount] > amount ? -1 : dp[amount];
}

import 'dart:collection';

// ── Counting characters — LinkedHashMap (default) ──
Map<String, int> countChars(String s) {
  final counts = <String, int>{};
  for (final c in s.split('')) {
    counts.update(c, (v) => v + 1, ifAbsent: () => 1);
  }
  return counts;
}

// ── Group by — using fold and putIfAbsent ──
Map<String, List<User>> groupByCity(List<User> users) {
  final out = <String, List<User>>{};
  for (final u in users) {
    out.putIfAbsent(u.city, () => <User>[]).add(u);
  }
  return out;
}

// ── HashSet — fast membership test, no order ──
bool hasDuplicate(List<int> nums) {
  final seen = HashSet<int>();
  for (final n in nums) {
    if (!seen.add(n)) return true;
  }
  return false;
}

