// ── LRU cache via LinkedHashMap (move-to-front on access) ──
class LruCache<K, V> {
  final int _maxSize;
  final _store = <K, V>{};
  LruCache(this._maxSize);

  V? get(K key) {
    final v = _store.remove(key);          // remove
    if (v != null) _store[key] = v;        // re-insert at end
    return v;
  }

  void put(K key, V value) {
    _store.remove(key);
    _store[key] = value;
    if (_store.length > _maxSize) {
      _store.remove(_store.keys.first);    // evict oldest insertion
    }
  }
}

// ── ❌ Recursive linked-list reverse — overflows on long lists ──
ListNode? reverseRecursive(ListNode? node, [ListNode? prev]) {
  if (node == null) return prev;
  final next = node.next;
  node.next = prev;
  return reverseRecursive(next, node);            // even though tail position
}

// ── ✅ Iterative — O(n) time, O(1) space, stack-safe ──
ListNode? reverseIterative(ListNode? head) {
  ListNode? prev;
  var cur = head;
  while (cur != null) {
    final next = cur.next;
    cur.next = prev;
    prev = cur;
    cur = next;
  }
  return prev;
}

// ── ❌ Recursive directory walk — explodes on deep filesystems ──
List<File> walkRecursive(Directory dir) {
  final out = <File>[];
  for (final entity in dir.listSync()) {
    if (entity is File) out.add(entity);
    if (entity is Directory) out.addAll(walkRecursive(entity));
  }
  return out;
}

// ── ✅ Iterative with explicit stack ──
Iterable<File> walkIterative(Directory root) sync* {
  final stack = <Directory>[root];
  while (stack.isNotEmpty) {
    final dir = stack.removeLast();
    for (final entity in dir.listSync()) {
      if (entity is File) yield entity;
      if (entity is Directory) stack.add(entity);
    }
  }
}

// ── Convert recursive DP to iterative table ──
// Recursive Fibonacci with memoization is fine for small n; for big n,
// the table form is both faster and stack-safe.
int fibTable(int n) {
  if (n <= 1) return n;
  var a = 0, b = 1;
  for (var i = 2; i <= n; i++) {
    final next = a + b;
    a = b;
    b = next;
  }
  return b;
}

