// ── dart:ffi — appropriate for hot CPU work ─────
import 'dart:ffi';
import 'package:ffi/ffi.dart';

typedef _BlurC    = Void Function(Pointer<Uint8>, Int32, Int32, Int32);
typedef _BlurDart = void Function(Pointer<Uint8>, int, int, int);

final _lib = DynamicLibrary.open(_libName());
final _blur = _lib.lookupFunction<_BlurC, _BlurDart>('gaussian_blur');

void blurInPlace(Uint8List rgba, int w, int h, int radius) {
  final ptr = calloc<Uint8>(rgba.length);
  try {
    ptr.asTypedList(rgba.length).setAll(0, rgba);
    _blur(ptr, w, h, radius);                  // direct C call
    rgba.setAll(0, ptr.asTypedList(rgba.length));
  } finally {
    calloc.free(ptr);
  }
}

// Hybrid example: MethodChannel asks the platform for the photo path,
// FFI does the actual pixel work without paying channel overhead per frame.

import 'dart:isolate';
import 'package:flutter/services.dart';

// 1. Root isolate captures the token and spawns a background isolate
Future<String> hashViaPlatform(String path) async {
  final token = RootIsolateToken.instance!;
  return Isolate.run(() async {
    // 2. Bind the messenger BEFORE any channel use
    BackgroundIsolateBinaryMessenger.ensureInitialized(token);

    // 3. Now MethodChannel works inside the background isolate
    const ch = MethodChannel('com.example/native');
    final hash = await ch.invokeMethod<String>('hashFile', {'path': path});
    return hash ?? '';
  });
}

// ── Native-driven background isolate (e.g. android_alarm_manager_plus) ──
// The native side wakes the engine in headless mode and spawns this entry:
@pragma('vm:entry-point')
Future<void> headlessWorker(Map<String, dynamic> payload) async {
  final token = payload['token'] as RootIsolateToken;
  BackgroundIsolateBinaryMessenger.ensureInitialized(token);

  // Now safe to use plugins — secure storage, http, sqflite, etc.
  const tokens = FlutterSecureStorage();
  final accessToken = await tokens.read(key: 'access_token');
  if (accessToken == null) return;

  await syncEngine.runOnce(accessToken);
}

