Future<void> _saveAndPop(BuildContext context) async {
  final messenger = ScaffoldMessenger.of(context);   // ✅ capture before await
  final navigator = Navigator.of(context);
  await api.save(form);
  // ❌ Don't use context here — widget may be gone
  messenger.showSnackBar(const SnackBar(content: Text('Saved')));
  navigator.pop();
}

// ── context.mounted (Flutter 3.7+) ──
Future<void> _alt(BuildContext context) async {
  await api.save(form);
  if (!context.mounted) return;     // ✅ short-circuit on unmount
  Navigator.of(context).pop();
}

